#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <comp421/hardware.h>
#include <comp421/yalnix.h>
#include <comp421/loadinfo.h>

/* Global variables */
int vm_enabled = 0;
void *kernel_brk_val;

struct pte *region1_pt;

typedef struct pcb {
    int pid;
    struct pte *region0_pt;
    SavedContext ctx;
    struct pcb *next;
    struct pcb *prev;
    // For Lab 2, we'll need more fields later (parent, children, exit status, etc.)
} pcb_t;

pcb_t *current_process = NULL;
pcb_t *idle_pcb = NULL;
pcb_t *init_pcb = NULL;

/* Ready queue */
pcb_t *ready_queue_head = NULL;
pcb_t *ready_queue_tail = NULL;

/* Physical memory management */
typedef struct free_frame {
    int pfn;
    struct free_frame *next;
} free_frame_t;

free_frame_t *free_frames_head = NULL;
int total_free_frames = 0;

/* Interrupt vector table */
void (*interrupt_vector[TRAP_VECTOR_SIZE])(ExceptionInfo *);

/* Function prototypes */
void trap_kernel_handler(ExceptionInfo *info);
void trap_clock_handler(ExceptionInfo *info);
void trap_illegal_handler(ExceptionInfo *info);
void trap_memory_handler(ExceptionInfo *info);
void trap_math_handler(ExceptionInfo *info);
void trap_tty_receive_handler(ExceptionInfo *info);
void trap_tty_transmit_handler(ExceptionInfo *info);

void scheduler(void);
SavedContext *MySwitchFunc(SavedContext *ctxp, void *p1, void *p2);

/* Helper functions for physical memory */
int allocate_frame(void) {
    if (free_frames_head == NULL) {
        return -1;
    }
    free_frame_t *node = free_frames_head;
    int pfn = node->pfn;
    free_frames_head = node->next;
    free(node);
    total_free_frames--;
    return pfn;
}

void free_frame(int pfn) {
    free_frame_t *node = (free_frame_t *)malloc(sizeof(free_frame_t));
    node->pfn = pfn;
    node->next = free_frames_head;
    free_frames_head = node;
    total_free_frames++;
}

/*
 * SetKernelBrk - Adjust the kernel heap break.
 */
int
SetKernelBrk(void *addr)
{
    void *new_brk = (void *)UP_TO_PAGE(addr);
    if (!vm_enabled) {
        kernel_brk_val = new_brk;
    } else {
        // Need to allocate physical pages and map them
        while (kernel_brk_val < new_brk) {
            int pfn = allocate_frame();
            if (pfn == -1) {
                return -1;
            }
            int vpn = ((unsigned long)kernel_brk_val - VMEM_1_BASE) >> PAGESHIFT;
            region1_pt[vpn].pfn = pfn;
            region1_pt[vpn].valid = 1;
            region1_pt[vpn].kprot = PROT_READ | PROT_WRITE;
            region1_pt[vpn].uprot = PROT_NONE;
            kernel_brk_val = (void *)((unsigned long)kernel_brk_val + PAGESIZE);
        }
        WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_1);
    }
    return 0;
}

/* Trap Handlers - Stubs for now */
void trap_kernel_handler(ExceptionInfo *info) {
    TracePrintf(1, "TRAP_KERNEL: code %d\n", info->code);
    info->regs[0] = ERROR; // Default return error
}

void trap_clock_handler(ExceptionInfo *info) {
    (void)info;
    TracePrintf(2, "TRAP_CLOCK\n");
    // scheduler();
}

void trap_illegal_handler(ExceptionInfo *info) {
    TracePrintf(0, "TRAP_ILLEGAL: code %d, pc %p\n", info->code, info->pc);
    Halt();
}

void trap_memory_handler(ExceptionInfo *info) {
    TracePrintf(0, "TRAP_MEMORY: code %d, addr %p, pc %p\n", info->code, info->addr, info->pc);
    Halt();
}

void trap_math_handler(ExceptionInfo *info) {
    TracePrintf(0, "TRAP_MATH: code %d, pc %p\n", info->code, info->pc);
    Halt();
}

void trap_tty_receive_handler(ExceptionInfo *info) {
