}

void trap_tty_transmit_handler(ExceptionInfo *info) {
    TracePrintf(1, "TRAP_TTY_TRANSMIT: code %d\n", info->code);
}

/* KernelStart */
void
KernelStart(ExceptionInfo *info, unsigned int pmem_size,
            void *orig_brk, char **cmd_args)
{
    int i;
    TracePrintf(0, "KernelStart: pmem_size %u, orig_brk %p\n", pmem_size, orig_brk);

    kernel_brk_val = orig_brk;

    /* 1. Initialize interrupt vector table */
    for (i = 0; i < TRAP_VECTOR_SIZE; i++) {
        interrupt_vector[i] = NULL;
    }
    interrupt_vector[TRAP_KERNEL] = trap_kernel_handler;
    interrupt_vector[TRAP_CLOCK] = trap_clock_handler;
    interrupt_vector[TRAP_ILLEGAL] = trap_illegal_handler;
    interrupt_vector[TRAP_MEMORY] = trap_memory_handler;
    interrupt_vector[TRAP_MATH] = trap_math_handler;
    interrupt_vector[TRAP_TTY_RECEIVE] = trap_tty_receive_handler;
    interrupt_vector[TRAP_TTY_TRANSMIT] = trap_tty_transmit_handler;

    WriteRegister(REG_VECTOR_BASE, (RCS421RegVal)interrupt_vector);

    /* 2. Initialize physical memory free list */
    // Physical pages from 0 to pmem_size/PAGESIZE
    // Exclude MEM_INVALID_PAGES at the bottom? 
    // Actually, hardware says we can use physical page 0, just not address 0.
    // But let's avoid physical pages used by the kernel.
    // Kernel is from VMEM_1_BASE up to kernel_brk_val.
    // We also need to allocate Region 1 page table.

    region1_pt = (struct pte *)malloc(PAGE_TABLE_SIZE);
    // After this, kernel_brk_val has moved.

    unsigned long kernel_start_pfn = VMEM_1_BASE >> PAGESHIFT;
    unsigned long kernel_end_pfn = UP_TO_PAGE(kernel_brk_val) >> PAGESHIFT;

    // Also include the kernel stack?
    // The boot ROM's kernel stack is at physical KERNEL_STACK_BASE to KERNEL_STACK_LIMIT.
    unsigned long kstack_start_pfn = KERNEL_STACK_BASE >> PAGESHIFT;
    unsigned long kstack_end_pfn = KERNEL_STACK_LIMIT >> PAGESHIFT;

    for (i = 0; i < (int)(pmem_size >> PAGESHIFT); i++) {
        if (i >= (int)kstack_start_pfn && i < (int)kstack_end_pfn) {
            continue; // Used by initial kernel stack
        }
        if (i >= (int)kernel_start_pfn && i < (int)kernel_end_pfn) {
            continue; // Used by kernel text/data/heap
        }
        if (i < (int)MEM_INVALID_PAGES) {
            // These are valid physical pages, but let's keep them free.
            // Wait, hardware says "any address in this range cannot be used as an address".
            // This applies to both physical and virtual.
            // So we can't even access physical page 0 if we use its physical address.
            // But we shouldn't be using physical addresses once VM is enabled.
            // Let's just include them in the free list.
        }
        free_frame(i);
    }

    /* 3. Initialize Region 1 page table (Identity Mapping for kernel) */
    for (i = 0; i < PAGE_TABLE_LEN; i++) {
        unsigned long vpn = i;
        unsigned long vaddr = VMEM_1_BASE + (vpn << PAGESHIFT);
        if (vaddr < (unsigned long)UP_TO_PAGE(kernel_brk_val)) {
            region1_pt[i].valid = 1;
            region1_pt[i].pfn = (VMEM_1_BASE >> PAGESHIFT) + i;
            if (vaddr < (unsigned long)&_etext) {
                region1_pt[i].kprot = PROT_READ | PROT_EXEC;
            } else {
                region1_pt[i].kprot = PROT_READ | PROT_WRITE;
            }
            region1_pt[i].uprot = PROT_NONE;
        } else {
            region1_pt[i].valid = 0;
        }
    }

    /* 4. Initialize Region 0 page table for init process */
    // For now, let's just map the kernel stack.
    init_pcb = (pcb_t *)malloc(sizeof(pcb_t));
    init_pcb->pid = 1;
    init_pcb->region0_pt = (struct pte *)malloc(PAGE_TABLE_SIZE);
    for (i = 0; i < PAGE_TABLE_LEN; i++) {
        unsigned long vaddr = (unsigned long)i << PAGESHIFT;
        if (vaddr >= KERNEL_STACK_BASE && vaddr < KERNEL_STACK_LIMIT) {
            init_pcb->region0_pt[i].valid = 1;
            init_pcb->region0_pt[i].pfn = i >> PAGESHIFT;
            init_pcb->region0_pt[i].kprot = PROT_READ | PROT_WRITE;
            init_pcb->region0_pt[i].uprot = PROT_NONE;
        } else {
            init_pcb->region0_pt[i].valid = 0;
        }
    }

    /* 5. Enable virtual memory */
    WriteRegister(REG_PTR1, (RCS421RegVal)region1_pt);
    WriteRegister(REG_PTR0, (RCS421RegVal)init_pcb->region0_pt);
    WriteRegister(REG_VM_ENABLE, 1);
    vm_enabled = 1;

    TracePrintf(0, "Virtual Memory Enabled\n");

    /* TODO: Create idle process, Load init program, etc. */

    // For now, let's just Halt to see if it gets this far.
    // Halt();
}

