    for (i = 0; i < PAGE_TABLE_LEN; i++) {
        unsigned long vaddr = (unsigned long)i << PAGESHIFT;
        if (vaddr >= KERNEL_STACK_BASE && vaddr < KERNEL_STACK_LIMIT) {
