/* LoadProgram implementation */
int
LoadProgram(char *name, char **args, ExceptionInfo *info)
{
    int fd;
    int status;
    struct loadinfo li;
    char *cp;
    char *cp2;
    char **cpp;
    char *argbuf;
    int i;
    unsigned long argcount;
    int size;
    int text_npg;
    int data_bss_npg;
    int stack_npg;

    TracePrintf(0, "LoadProgram '%s', args %p\n", name, args);

    if ((fd = open(name, O_RDONLY)) < 0) {
	TracePrintf(0, "LoadProgram: can't open file '%s'\n", name);
	return (-1);
    }

    status = LoadInfo(fd, &li);
    if (status != LI_SUCCESS) {
	TracePrintf(0, "LoadProgram: LoadInfo error %d\n", status);
	close(fd);
	return (-1);
    }

    size = 0;
    for (i = 0; args[i] != NULL; i++) {
	size += strlen(args[i]) + 1;
    }
    argcount = i;

    cp = argbuf = (char *)malloc(size);
    for (i = 0; args[i] != NULL; i++) {
	strcpy(cp, args[i]);
	cp += strlen(cp) + 1;
    }

    cp = ((char *)USER_STACK_LIMIT) - size;
    cpp = (char **)((unsigned long)cp & (-1 << 4));
    cpp = (char **)((unsigned long)cpp - ((argcount + 4) * sizeof(void *)));

    text_npg = li.text_size >> PAGESHIFT;
    data_bss_npg = UP_TO_PAGE(li.data_size + li.bss_size) >> PAGESHIFT;
    stack_npg = (USER_STACK_LIMIT - DOWN_TO_PAGE(cpp)) >> PAGESHIFT;

    if (MEM_INVALID_PAGES + text_npg + data_bss_npg + 1 + stack_npg +
	1 + KERNEL_STACK_PAGES > PAGE_TABLE_LEN) {
	free(argbuf);
	close(fd);
	return (-1);
    }

    // Check physical memory
    int current_pages = 0;
    for (i = 0; i < PAGE_TABLE_LEN; i++) {
        unsigned long vaddr = (unsigned long)i << PAGESHIFT;
        if (vaddr >= KERNEL_STACK_BASE && vaddr < KERNEL_STACK_LIMIT) continue;
        if (current_process && current_process->region0_pt[i].valid) current_pages++;
    }
    if (text_npg + data_bss_npg + stack_npg > total_free_frames + current_pages) {
	free(argbuf);
	close(fd);
	return (-1);
    }

    info->sp = (void *)cpp;

    // Free old pages
    if (current_process) {
        for (i = 0; i < PAGE_TABLE_LEN; i++) {
            unsigned long vaddr = (unsigned long)i << PAGESHIFT;
            if (vaddr >= KERNEL_STACK_BASE && vaddr < KERNEL_STACK_LIMIT) continue;
            if (current_process->region0_pt[i].valid) {
                free_frame_pfn(current_process->region0_pt[i].pfn);
                current_process->region0_pt[i].valid = 0;
            }
        }
    }

    struct pte *pt = current_process ? current_process->region0_pt : init_pcb->region0_pt;

    for (i = 0; i < text_npg; i++) {
        pt[MEM_INVALID_PAGES + i].valid = 1;
        pt[MEM_INVALID_PAGES + i].pfn = allocate_frame();
        pt[MEM_INVALID_PAGES + i].kprot = PROT_READ | PROT_WRITE;
        pt[MEM_INVALID_PAGES + i].uprot = PROT_READ | PROT_EXEC;
    }
    for (i = 0; i < data_bss_npg; i++) {
        pt[MEM_INVALID_PAGES + text_npg + i].valid = 1;
        pt[MEM_INVALID_PAGES + text_npg + i].pfn = allocate_frame();
        pt[MEM_INVALID_PAGES + text_npg + i].kprot = PROT_READ | PROT_WRITE;
        pt[MEM_INVALID_PAGES + text_npg + i].uprot = PROT_READ | PROT_WRITE;
    }
    for (i = 0; i < stack_npg; i++) {
        int vpn = (USER_STACK_LIMIT >> PAGESHIFT) - stack_npg + i;
        pt[vpn].valid = 1;
        pt[vpn].pfn = allocate_frame();
        pt[vpn].kprot = PROT_READ | PROT_WRITE;
        pt[vpn].uprot = PROT_READ | PROT_WRITE;
    }

    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);

    if (read(fd, (void *)MEM_INVALID_SIZE, li.text_size+li.data_size)
	!= (ssize_t)(li.text_size+li.data_size)) {
	free(argbuf);
	close(fd);
	return (-2);
    }
    close(fd);

    for (i = 0; i < text_npg; i++) {
        pt[MEM_INVALID_PAGES + i].kprot = PROT_READ | PROT_EXEC;
    }
    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);

    memset((void *)(MEM_INVALID_SIZE + li.text_size + li.data_size),
	'\0', li.bss_size);

    info->pc = (void *)li.entry;

    *cpp++ = (char *)argcount;
    cp2 = argbuf;
    for (i = 0; (unsigned long)i < argcount; i++) {
	*cpp++ = cp;
	strcpy(cp, cp2);
	cp += strlen(cp) + 1;
	cp2 += strlen(cp2) + 1;
    }
    free(argbuf);
    *cpp++ = NULL;
    *cpp++ = NULL;
    *cpp++ = 0;

    for (i = 0; i < NUM_REGS; i++) info->regs[i] = 0;
    info->psr = 0;

    return (0);
}

void MyIdleProcess(void) {
    while(1) {
        TracePrintf(2, "Idle process running...\n");
        Pause();
    }
}

SavedContext *SaveContextFunc(SavedContext *ctxp, void *p1, void *p2) {
    (void)p1; (void)p2;
    return ctxp;
}

/* KernelStart */
void
KernelStart(ExceptionInfo *info, unsigned int pmem_size,
            void *orig_brk, char **cmd_args)
{
    int i;
    TracePrintf(0, "KernelStart: pmem_size %u, orig_brk %p\n", pmem_size, orig_brk);

    kernel_brk_val = orig_brk;

    for (i = 0; i < TRAP_VECTOR_SIZE; i++) interrupt_vector[i] = NULL;
    interrupt_vector[TRAP_KERNEL] = trap_kernel_handler;
    interrupt_vector[TRAP_CLOCK] = trap_clock_handler;
    interrupt_vector[TRAP_ILLEGAL] = trap_illegal_handler;
    interrupt_vector[TRAP_MEMORY] = trap_memory_handler;
    interrupt_vector[TRAP_MATH] = trap_math_handler;
    interrupt_vector[TRAP_TTY_RECEIVE] = trap_tty_receive_handler;
    interrupt_vector[TRAP_TTY_TRANSMIT] = trap_tty_transmit_handler;

    WriteRegister(REG_VECTOR_BASE, (RCS421RegVal)interrupt_vector);

    region1_pt = (struct pte *)malloc(PAGE_TABLE_SIZE);

    unsigned long kernel_start_pfn = VMEM_1_BASE >> PAGESHIFT;
    unsigned long kernel_end_pfn = UP_TO_PAGE(kernel_brk_val) >> PAGESHIFT;
    unsigned long kstack_start_pfn = KERNEL_STACK_BASE >> PAGESHIFT;
    unsigned long kstack_end_pfn = KERNEL_STACK_LIMIT >> PAGESHIFT;

    for (i = 0; i < (int)(pmem_size >> PAGESHIFT); i++) {
        if (i >= (int)kstack_start_pfn && i < (int)kstack_end_pfn) continue;
        if (i >= (int)kernel_start_pfn && i < (int)kernel_end_pfn) continue;
        free_frame_pfn(i);
    }

    for (i = 0; i < PAGE_TABLE_LEN; i++) {
        unsigned long vaddr = VMEM_1_BASE + ((unsigned long)i << PAGESHIFT);
        if (vaddr < (unsigned long)UP_TO_PAGE(kernel_brk_val)) {
            region1_pt[i].valid = 1;
            region1_pt[i].pfn = (VMEM_1_BASE >> PAGESHIFT) + i;
            if (vaddr < (unsigned long)&_etext) region1_pt[i].kprot = PROT_READ | PROT_EXEC;
            else region1_pt[i].kprot = PROT_READ | PROT_WRITE;
            region1_pt[i].uprot = PROT_NONE;
        } else {
            region1_pt[i].valid = 0;
        }
    }

    // Create IDLE process first to save its context
    idle_pcb = create_pcb();
    idle_pcb->pid = 0;

    // Switch to IDLE's page table temporarily to save context
    WriteRegister(REG_PTR0, (RCS421RegVal)idle_pcb->region0_pt);
    if (ContextSwitch(SaveContextFunc, &idle_pcb->ctx, idle_pcb, NULL) == 0) {
        MyIdleProcess();
    }

    // Now create INIT process
    init_pcb = create_pcb();
    init_pcb->pid = 1;
    current_process = init_pcb;

    WriteRegister(REG_PTR1, (RCS421RegVal)region1_pt);
    WriteRegister(REG_PTR0, (RCS421RegVal)init_pcb->region0_pt);
    WriteRegister(REG_VM_ENABLE, 1);
    vm_enabled = 1;

    char *init_prog = (cmd_args && cmd_args[0]) ? cmd_args[0] : "init";
    if (LoadProgram(init_prog, cmd_args ? cmd_args : (char *[]){"init", NULL}, info) < 0) {
        TracePrintf(0, "KernelStart: Failed to load init program\n");
        Halt();
    }
}

